    scope=None,
    include_client_id: bool = False,
    **kwargs
) -> str:
    params = parse_qsl(body, keep_blank_values=True)

    params.append(('grant_type', 'client_credentials'))

    if scope is not None:
        if isinstance(scope, list):
            scope_str = ' '.join(scope)
        else:
            scope_str = scope
        if scope_str.strip():
            params.append(('scope', scope_str))

    if include_client_id:
        params.append(('client_id', client_id))

    for key, value in kwargs.items():
        params.append((key, value))

    return urlencode(params)

from urllib.parse import urlencode, parse_qsl

def build_revocation_body(token, token_type_hint="access_token", body="", **kwargs):
    # Parse existing body preserving order
    existing = parse_qsl(body, keep_blank_values=True)
    existing_keys = {k for k, v in existing}

    new_params = []

    if "token" not in existing_keys:
        new_params.append(("token", token))

    if token_type_hint is not None and "token_type_hint" not in existing_keys:
        new_params.append(("token_type_hint", token_type_hint))

    for k, v in kwargs.items():
        if k not in existing_keys and k not in {p[0] for p in new_params}:
            new_params.append((k, v))

    all_params = existing + new_params
    return urlencode(all_params)

import json
import warnings

def parse_token_response(body, scope=None):
    # Parse JSON
    try:
        params = json.loads(body)
    except (ValueError, TypeError):
        raise ValueError("Invalid JSON in token response body")

    # Check for error key first
    if "error" in params:
        raise ValueError(params["error"])

    # Check for access_token
    if "access_token" not in params:
        raise ValueError("Missing access_token in token response")

    # Build result dict
    result = dict(params)

    # Convert expires_in to int if present
    if "expires_in" in result:
        result["expires_in"] = int(result["expires_in"])

    # Convert scope string to list if present
    response_scope_set = None
    if "scope" in result:
        if isinstance(result["scope"], str):
            scope_list = result["scope"].split()
            result["scope"] = scope_list
            response_scope_set = set(scope_list)
        elif isinstance(result["scope"], list):
            response_scope_set = set(result["scope"])

    # Scope change warning
    if scope is not None and response_scope_set is not None:
        if isinstance(scope, list):
            requested_scope_set = set(scope)
        else:
            requested_scope_set = set(scope.split())
        if requested_scope_set != response_scope_set:
            warnings.warn(
                "Response scope has changed from requested scope",
                Warning
            )

    return result

