import hashlib
import base64
import secrets
import string

class PKCEHelper:
    _UNRESERVED = string.ascii_uppercase + string.ascii_lowercase + string.digits + '-._~'

    def create_code_verifier(self, length: int) -> str:
        if not (43 <= length <= 128):
            raise ValueError(f'length must be between 43 and 128 inclusive, got {length}')
        return ''.join(secrets.choice(self._UNRESERVED) for _ in range(length))

    def create_code_challenge(self, code_verifier: str, code_challenge_method: str = None) -> str:
        if code_challenge_method is None or code_challenge_method == 'plain':
            return code_verifier
        if code_challenge_method == 'S256':
            digest = hashlib.sha256(code_verifier.encode('ascii')).digest()
            return base64.urlsafe_b64encode(digest).rstrip(b'=').decode('ascii')
        raise ValueError(f'Unsupported code_challenge_method: {code_challenge_method}')

