def serialize_scopes(scopes: list) -> str:
    unique_sorted = sorted(set(t for t in scopes if t))
    return ' '.join(unique_sorted)

def scopes_valid(requested: str, granted: str) -> bool:
    requested_set = set(requested.split())
    granted_set = set(granted.split())
    return requested_set.issubset(granted_set)

