    if not scope_string:
        return []
    return scope_string.split()


def validate_scopes(requested_scopes, allowed_scopes):
    if isinstance(requested_scopes, str) or isinstance(allowed_scopes, str):
        raise ValueError("invalid: scope parameters must be list-like, not strings")
    try:
        allowed_set = set(allowed_scopes)
        return all(scope in allowed_set for scope in requested_scopes)
    except TypeError as e:
        raise ValueError(f"invalid scope argument: {e}")

