class MinimalOAuthClient:
    def __init__(self, client_id=None, client_secret=None,
                 token_endpoint_auth_method='client_secret_basic',
                 scope=None, redirect_uri=None):
        self._client_id = client_id
        self._client_secret = client_secret
        self._token_endpoint_auth_method = token_endpoint_auth_method
        self._scope = scope
        self._redirect_uri = redirect_uri

    @property
    def metadata(self):
        return {
            'client_id': self._client_id,
            'client_secret': self._client_secret,
            'token_endpoint_auth_method': self._token_endpoint_auth_method,
            'scope': self._scope,
            'redirect_uri': self._redirect_uri,
        }

    @property
    def client_auth_method(self):
        return self._token_endpoint_auth_method

    def get_redirect_uri(self):
        return self._redirect_uri

    def get_default_scope(self):
        if not self._scope:
            return []
        return self._scope.split()

    def check_redirect_uri(self, uri):
        if self._redirect_uri is None:
            return True
        return uri == self._redirect_uri

